import type { Ref } from 'vue'
import { createContext } from 'reka-ui'

export interface AutocompleteContext {
  searchTerm: Ref<string>
}

const [injectAutocompleteContext, provideAutocompleteContext] =
  createContext<AutocompleteContext>('AutocompleteContext')

export { provideAutocompleteContext }

const requiredKeys: (keyof AutocompleteContext)[] = ['searchTerm']
/**
 * Hook to access the Autocomplete context within sub-components.
 *
 * @returns The shared Autocomplete context.
 * @throws Error if called outside of an `<Autocomplete>` component tree.
 */
export function useAutocompleteContext(): AutocompleteContext {
  const ctx = injectAutocompleteContext()

  if (!ctx) {
    throw new Error(
      '[Autocomplete] useAutocompleteContext() was called outside of an <Autocomplete> component.\n' +
        'Make sure your component is rendered inside an <Autocomplete> root.',
    )
  }
  const missingKeys = requiredKeys.filter(key => ctx[key] === undefined)
  if (missingKeys.length > 0) {
    throw new Error(
      `[Autocomplete] Missing required context property: "${missingKeys.join(', ')}".`,
    )
  }
  return ctx
}

import type { ComboboxRootEmits, ComboboxRootProps } from 'reka-ui'

export type AutocompleteProps = ComboboxRootProps & {
  searchTerm?: string
}

export type AutocompleteEmits = ComboboxRootEmits & {
  'update:searchTerm': [searchTerm: string]
}

import type { Ref } from 'vue'
import type { ShowMoreRootContext } from './types'
import { createContext } from 'reka-ui'

export const [injectShowMoreRootContext, provideShowMoreRootContext] =
  createContext<ShowMoreRootContext>('ShowMoreRootContext')

export const [injectShowMoreItemContext, provideShowMoreItemContext] = createContext<{
  value: string
  isTruncated: Ref<boolean>
}>('ShowMoreItemContext')

const requiredKeys: (keyof ShowMoreRootContext)[] = [
  'threshold',
  'truncationType',
  'fade',
  'forceMount',
  'showToggle',
  'open',
  'lineHeight',
]

export function useShowMoreRootContext(): ShowMoreRootContext {
  const ctx = injectShowMoreRootContext()

  if (!ctx) {
    throw new Error('[ShowMore] useShowMoreRootContext() was called outside of <ShowMore>.')
  }

  const missingKeys = requiredKeys.filter(key => ctx[key] === undefined)
  if (missingKeys.length > 0) {
    throw new Error(`[ShowMore] Missing required context property: "${missingKeys.join(', ')}".`)
  }

  return ctx
}

export function useShowMoreItemContext() {
  const ctx = injectShowMoreItemContext()
  if (!ctx) {
    throw new Error('[ShowMore] useShowMoreItemContext() was called outside of <ShowMoreItem>.')
  }
  return ctx
}
